func (s *TransactionServer) CreateTransaction(ctx context.Context, req *CreateTransactionRequest) (*pb.CreateTransactionResponse, error) {
	// Validate request
	if err := s.validateCreateRequest(req); err != nil {
		return nil, err
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	// Check idempotency key
	if req.IdempotencyKey != "" {
		if existingTxID, ok := s.idempotencyKeys[req.IdempotencyKey]; ok {
			tx := s.transactions[existingTxID]
			return &pb.CreateTransactionResponse{Transaction: tx}, nil
		}
	}

	// Validate accounts exist
	if req.Type == pb.TransactionType_TRANSACTION_TYPE_TRANSFER ||
		req.Type == pb.TransactionType_TRANSACTION_TYPE_WITHDRAWAL {
		if _, ok := s.balances[req.SourceAccountId]; !ok {
			return nil, status.Errorf(codes.NotFound, "source account %s not found", req.SourceAccountId)
		}
	}

	if req.Type == pb.TransactionType_TRANSACTION_TYPE_TRANSFER ||
		req.Type == pb.TransactionType_TRANSACTION_TYPE_DEPOSIT {
		if _, ok := s.balances[req.DestinationAccountId]; !ok {
			return nil, status.Errorf(codes.NotFound, "destination account %s not found", req.DestinationAccountId)
		}
	}

	// Check sufficient funds for withdrawals and transfers
	if req.Type == pb.TransactionType_TRANSACTION_TYPE_WITHDRAWAL ||
		req.Type == pb.TransactionType_TRANSACTION_TYPE_TRANSFER {
		srcBalance := s.balances[req.SourceAccountId]
		if srcBalance.AvailableMinorUnits < req.Amount.AmountMinorUnits {
			return nil, status.Errorf(codes.FailedPrecondition,
				"insufficient funds: available %d, requested %d",
				srcBalance.AvailableMinorUnits, req.Amount.AmountMinorUnits)
		}
	}

	// Create the transaction
	txID := uuid.New().String()
	now := time.Now().UTC().Format(time.RFC3339Nano)

	transaction := &pb.Transaction{
		TransactionId:        txID,
		SourceAccountId:      req.SourceAccountId,
		DestinationAccountId: req.DestinationAccountId,
		Amount:               req.Amount,
		Type:                 req.Type,
		Status:               pb.TransactionStatus_TRANSACTION_STATUS_PENDING,
		Description:          req.Description,
		CreatedAt:            now,
		UpdatedAt:            now,
		IdempotencyKey:       req.IdempotencyKey,
	}

	// Process the transaction (update balances)
	if err := s.processTransaction(transaction); err != nil {
		transaction.Status = pb.TransactionStatus_TRANSACTION_STATUS_FAILED
		s.transactions[txID] = transaction
		return nil, status.Errorf(codes.Internal, "failed to process transaction: %v", err)
	}

	transaction.Status = pb.TransactionStatus_TRANSACTION_STATUS_COMPLETED
	transaction.UpdatedAt = time.Now().UTC().Format(time.RFC3339Nano)

	// Store the transaction
	s.transactions[txID] = transaction

	// Store idempotency key mapping
	if req.IdempotencyKey != "" {
		s.idempotencyKeys[req.IdempotencyKey] = txID
	}

	// Index by account
	if req.SourceAccountId != "" {
		s.txByAccount[req.SourceAccountId] = append(s.txByAccount[req.SourceAccountId], txID)
	}
	if req.DestinationAccountId != "" && req.DestinationAccountId != req.SourceAccountId {
		s.txByAccount[req.DestinationAccountId] = append(s.txByAccount[req.DestinationAccountId], txID)
	}

	return &pb.CreateTransactionResponse{Transaction: transaction}, nil
}

