type CreateTransactionRequest = pb.CreateTransactionRequest

func (s *TransactionServer) validateCreateRequest(req *pb.CreateTransactionRequest) error {
	if req.Amount == nil {
		return status.Error(codes.InvalidArgument, "amount is required")
	}

	if req.Amount.AmountMinorUnits <= 0 {
		return status.Error(codes.InvalidArgument, "amount must be positive")
	}

	if req.Amount.Currency == "" {
		return status.Error(codes.InvalidArgument, "currency is required")
	}

	if req.Type == pb.TransactionType_TRANSACTION_TYPE_UNSPECIFIED {
		return status.Error(codes.InvalidArgument, "transaction type is required")
	}

	switch req.Type {
	case pb.TransactionType_TRANSACTION_TYPE_TRANSFER:
		if req.SourceAccountId == "" || req.DestinationAccountId == "" {
			return status.Error(codes.InvalidArgument, "both source and destination accounts required for transfer")
		}
		if req.SourceAccountId == req.DestinationAccountId {
			return status.Error(codes.InvalidArgument, "source and destination accounts must be different")
		}
	case pb.TransactionType_TRANSACTION_TYPE_DEPOSIT:
		if req.DestinationAccountId == "" {
			return status.Error(codes.InvalidArgument, "destination account required for deposit")
		}
	case pb.TransactionType_TRANSACTION_TYPE_WITHDRAWAL:
		if req.SourceAccountId == "" {
			return status.Error(codes.InvalidArgument, "source account required for withdrawal")
		}
	}

	return nil
}

func (s *TransactionServer) processTransaction(tx *pb.Transaction) error {
	amount := tx.Amount.AmountMinorUnits

	switch tx.Type {
	case pb.TransactionType_TRANSACTION_TYPE_DEPOSIT:
		destBalance := s.balances[tx.DestinationAccountId]
		destBalance.AvailableMinorUnits += amount

	case pb.TransactionType_TRANSACTION_TYPE_WITHDRAWAL:
		srcBalance := s.balances[tx.SourceAccountId]
		if srcBalance.AvailableMinorUnits < amount {
			return fmt.Errorf("insufficient funds")
		}
		srcBalance.AvailableMinorUnits -= amount

	case pb.TransactionType_TRANSACTION_TYPE_TRANSFER:
		srcBalance := s.balances[tx.SourceAccountId]
		destBalance := s.balances[tx.DestinationAccountId]

		if srcBalance.AvailableMinorUnits < amount {
			return fmt.Errorf("insufficient funds")
		}

		srcBalance.AvailableMinorUnits -= amount
		destBalance.AvailableMinorUnits += amount

	default:
		return fmt.Errorf("unsupported transaction type: %v", tx.Type)
	}

	return nil
}

func (s *TransactionServer) GetBalance(ctx context.Context, req *pb.GetBalanceRequest) (*pb.GetBalanceResponse, error) {
	if req.AccountId == "" {
		return nil, status.Error(codes.InvalidArgument, "account_id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	balance, ok := s.balances[req.AccountId]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "account %s not found", req.AccountId)
	}

	currency := balance.Currency
	if req.Currency != "" && req.Currency != balance.Currency {
		return nil, status.Errorf(codes.InvalidArgument, "account currency is %s, requested %s", balance.Currency, req.Currency)
	}

	return &pb.GetBalanceResponse{
		AccountId: req.AccountId,
		AvailableBalance: &pb.Money{
			AmountMinorUnits: balance.AvailableMinorUnits,
			Currency:         currency,
		},
		PendingBalance: &pb.Money{
			AmountMinorUnits: balance.PendingMinorUnits,
			Currency:         currency,
		},
		AsOf: time.Now().UTC().Format(time.RFC3339Nano),
	}, nil
}

