func (s *TransactionServer) ListTransactions(ctx context.Context, req *pb.ListTransactionsRequest) (*pb.ListTransactionsResponse, error) {
	if req.AccountId == "" {
		return nil, status.Error(codes.InvalidArgument, "account_id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	pageSize := int(req.PageSize)
	if pageSize <= 0 {
		pageSize = 50
	}
	if pageSize > 1000 {
		pageSize = 1000
	}

	txIDs, ok := s.txByAccount[req.AccountId]
	if !ok {
		return &pb.ListTransactionsResponse{
			Transactions:  []*pb.Transaction{},
			NextPageToken: "",
			TotalCount:    0,
		}, nil
	}

	// Simple pagination using index offset encoded as page_token
	startIdx := 0
	if req.PageToken != "" {
		fmt.Sscanf(req.PageToken, "%d", &startIdx)
	}

	var results []*pb.Transaction
	for i := startIdx; i < len(txIDs) && len(results) < pageSize; i++ {
		tx := s.transactions[txIDs[i]]

		// Apply date filters if provided
		if req.StartDate != "" {
			startDate, err := time.Parse(time.RFC3339, req.StartDate)
			if err == nil {
				txCreated, err := time.Parse(time.RFC3339Nano, tx.CreatedAt)
				if err == nil && txCreated.Before(startDate) {
					continue
				}
			}
		}

		if req.EndDate != "" {
			endDate, err := time.Parse(time.RFC3339, req.EndDate)
			if err == nil {
				txCreated, err := time.Parse(time.RFC3339Nano, tx.CreatedAt)
				if err == nil && txCreated.After(endDate) {
					continue
				}
			}
		}

		results = append(results, tx)
	}

	nextPageToken := ""
	nextIdx := startIdx + pageSize
	if nextIdx < len(txIDs) {
		nextPageToken = fmt.Sprintf("%d", nextIdx)
	}

	return &pb.ListTransactionsResponse{
		Transactions:  results,
		NextPageToken: nextPageToken,
		TotalCount:    int32(len(txIDs)),
	}, nil
}